import{c as l,Q as i,j as s,m as n}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"发布前检查清单","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/22-发布前检查清单.md","filePath":"mobileCommonLearning/22-发布前检查清单.md","lastUpdated":1780912084000}'),e={name:"mobileCommonLearning/22-发布前检查清单.md"};function p(t,a,o,r,d,c){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="发布前检查清单" tabindex="-1">发布前检查清单 <a class="header-anchor" href="#发布前检查清单" aria-label="Permalink to &quot;发布前检查清单&quot;">​</a></h1><p>移动端发版不要靠记忆。每次发布都应该有固定检查清单。</p><p>一句话:<strong>发布前检查不是流程装饰,是为了避免低级事故进线上。</strong></p><hr><h2 id="一、发布信息" tabindex="-1">一、发布信息 <a class="header-anchor" href="#一、发布信息" aria-label="Permalink to &quot;一、发布信息&quot;">​</a></h2><ul><li>[ ] 本次版本号是否确认</li><li>[ ] Android versionCode 是否递增</li><li>[ ] iOS build number 是否递增</li><li>[ ] 版本名称是否和产品、商店后台一致</li><li>[ ] release 分支或 tag 是否确认</li><li>[ ] 本次发布范围是否明确</li><li>[ ] 是否有回滚或止损方案</li><li>[ ] 是否明确发布负责人和值守人</li></ul><p>必须能回答:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个包对应哪个 commit?</span></span>
<span class="line"><span>这个包准备发哪些渠道?</span></span>
<span class="line"><span>出了问题谁决定暂停?</span></span></code></pre></div><hr><h2 id="二、包身份" tabindex="-1">二、包身份 <a class="header-anchor" href="#二、包身份" aria-label="Permalink to &quot;二、包身份&quot;">​</a></h2><ul><li>[ ] Android applicationId 是否正确</li><li>[ ] iOS Bundle ID 是否正确</li><li>[ ] App 名称是否正确</li><li>[ ] 图标是否正确</li><li>[ ] 启动图是否正确</li><li>[ ] 渠道标识是否正确</li><li>[ ] 环境配置是否是生产</li><li>[ ] 后端 API 地址是否是生产</li></ul><p>最危险的问题:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>测试环境配置打进生产包</span></span>
<span class="line"><span>生产签名打了测试包</span></span>
<span class="line"><span>渠道包串渠道</span></span></code></pre></div><p>这些问题必须在上传前查。</p><hr><h2 id="三、签名和证书" tabindex="-1">三、签名和证书 <a class="header-anchor" href="#三、签名和证书" aria-label="Permalink to &quot;三、签名和证书&quot;">​</a></h2><p>Android:</p><ul><li>[ ] release 包是否使用生产签名</li><li>[ ] keystore 指纹是否和渠道后台一致</li><li>[ ] AAB / APK 是否符合目标渠道要求</li><li>[ ] 是否没有使用 debug signingConfig</li></ul><p>iOS:</p><ul><li>[ ] Archive 是否使用正确 Team</li><li>[ ] Provisioning Profile 是否匹配 Bundle ID</li><li>[ ] entitlements 是否正确</li><li>[ ] export method 是否正确</li><li>[ ] dSYM 是否归档</li></ul><p>签名问题不要等商店报错再查。</p><hr><h2 id="四、功能回归" tabindex="-1">四、功能回归 <a class="header-anchor" href="#四、功能回归" aria-label="Permalink to &quot;四、功能回归&quot;">​</a></h2><p>至少覆盖:</p><ul><li>[ ] 首次安装启动</li><li>[ ] 老版本覆盖升级</li><li>[ ] 登录</li><li>[ ] 退出登录</li><li>[ ] 核心业务流程</li><li>[ ] 支付或下单</li><li>[ ] 推送注册和点击</li><li>[ ] Deep Link / Universal Link / App Link</li><li>[ ] WebView 页面</li><li>[ ] 权限申请和拒绝</li><li>[ ] 弱网和断网</li><li>[ ] 后台切前台</li></ul><p>回归要用 release 包。debug 包通过不代表 release 包没问题。</p><hr><h2 id="五、数据和兼容" tabindex="-1">五、数据和兼容 <a class="header-anchor" href="#五、数据和兼容" aria-label="Permalink to &quot;五、数据和兼容&quot;">​</a></h2><ul><li>[ ] 本地数据库迁移是否测过</li><li>[ ] 老版本升级后数据是否保留</li><li>[ ] 缓存格式变化是否兼容</li><li>[ ] 登录态是否正常迁移</li><li>[ ] 旧配置是否有兜底</li><li>[ ] 服务端接口是否兼容旧 App</li><li>[ ] 新 App 是否兼容当前线上服务端</li><li>[ ] 灰度期间新旧协议是否能共存</li></ul><p>移动端不能假设用户都会立刻升级。</p><p>服务端接口要同时服务多个 App 版本。</p><hr><h2 id="六、权限和隐私" tabindex="-1">六、权限和隐私 <a class="header-anchor" href="#六、权限和隐私" aria-label="Permalink to &quot;六、权限和隐私&quot;">​</a></h2><ul><li>[ ] 新增权限是否有产品和合规确认</li><li>[ ] 权限弹窗文案是否准确</li><li>[ ] 拒绝权限后是否有可用降级</li><li>[ ] 隐私政策是否覆盖新采集项</li><li>[ ] App Store 隐私标签是否更新</li><li>[ ] Android 数据安全表单是否更新</li><li>[ ] 第三方 SDK 清单是否更新</li><li>[ ] 是否没有过度采集通讯录、位置、相册等敏感数据</li></ul><p>权限问题会直接影响审核和用户信任。</p><hr><h2 id="七、性能和稳定性" tabindex="-1">七、性能和稳定性 <a class="header-anchor" href="#七、性能和稳定性" aria-label="Permalink to &quot;七、性能和稳定性&quot;">​</a></h2><ul><li>[ ] 冷启动是否没有明显回退</li><li>[ ] 包体积是否没有异常增长</li><li>[ ] 首页首屏是否正常</li><li>[ ] 低端机是否测过核心流程</li><li>[ ] 列表滚动是否流畅</li><li>[ ] 内存是否没有明显泄漏</li><li>[ ] 后台切回是否正常</li><li>[ ] 崩溃率是否在测试阶段可接受</li></ul><p>发布前至少对比上一版本:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>启动耗时</span></span>
<span class="line"><span>包体积</span></span>
<span class="line"><span>核心页面耗时</span></span>
<span class="line"><span>崩溃和 ANR</span></span></code></pre></div><hr><h2 id="八、监控和符号表" tabindex="-1">八、监控和符号表 <a class="header-anchor" href="#八、监控和符号表" aria-label="Permalink to &quot;八、监控和符号表&quot;">​</a></h2><ul><li>[ ] 崩溃 SDK 是否正常初始化</li><li>[ ] Android mapping 是否上传</li><li>[ ] iOS dSYM 是否上传</li><li>[ ] Flutter / RN 符号表或 sourcemap 是否上传</li><li>[ ] 关键业务异常是否上报</li><li>[ ] 网络 trace id 是否可关联</li><li>[ ] 版本号、build 号、渠道是否进入监控字段</li><li>[ ] 告警规则是否覆盖新版本</li></ul><p>没有符号表的新版本不应该发布。</p><hr><h2 id="九、商店和渠道材料" tabindex="-1">九、商店和渠道材料 <a class="header-anchor" href="#九、商店和渠道材料" aria-label="Permalink to &quot;九、商店和渠道材料&quot;">​</a></h2><ul><li>[ ] 更新说明是否准备</li><li>[ ] 截图是否符合当前版本</li><li>[ ] 隐私材料是否准备</li><li>[ ] 审核账号是否可用</li><li>[ ] 国内应用市场软著、备案、授权材料是否满足要求</li><li>[ ] Google Play / App Store 后台信息是否更新</li><li>[ ] 分阶段发布比例是否确认</li><li>[ ] 发布时间窗口是否避开高风险时段</li></ul><p>不要在无人值守时全量发布。</p><hr><h2 id="十、发布后观察" tabindex="-1">十、发布后观察 <a class="header-anchor" href="#十、发布后观察" aria-label="Permalink to &quot;十、发布后观察&quot;">​</a></h2><p>发布后至少观察:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>安装成功率</span></span>
<span class="line"><span>启动成功率</span></span>
<span class="line"><span>崩溃率</span></span>
<span class="line"><span>ANR 率</span></span>
<span class="line"><span>登录成功率</span></span>
<span class="line"><span>核心接口成功率</span></span>
<span class="line"><span>支付 / 下单成功率</span></span>
<span class="line"><span>推送 token 注册成功率</span></span>
<span class="line"><span>用户反馈和商店评论</span></span></code></pre></div><p>灰度发布建议:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1% -&gt; 5% -&gt; 20% -&gt; 50% -&gt; 100%</span></span></code></pre></div><p>每一步都要看数据,不是按时间自动冲到全量。</p><hr><h2 id="十一、发布前最后确认" tabindex="-1">十一、发布前最后确认 <a class="header-anchor" href="#十一、发布前最后确认" aria-label="Permalink to &quot;十一、发布前最后确认&quot;">​</a></h2><p>最后问三句话:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个包是不是我们要发的那个包?</span></span>
<span class="line"><span>这个包出了问题能不能快速止损?</span></span>
<span class="line"><span>这个包上线后有没有人看数据?</span></span></code></pre></div><p>如果任何一个答案不清楚,不要发布。</p><hr><h2 id="十二、结论" tabindex="-1">十二、结论 <a class="header-anchor" href="#十二、结论" aria-label="Permalink to &quot;十二、结论&quot;">​</a></h2><p>发布检查清单要固定、可执行、可追踪。</p><p>最小闭环:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>构建可追溯</span></span>
<span class="line"><span>签名可验证</span></span>
<span class="line"><span>功能已回归</span></span>
<span class="line"><span>材料已准备</span></span>
<span class="line"><span>监控已接入</span></span>
<span class="line"><span>灰度可暂停</span></span>
<span class="line"><span>事故有预案</span></span></code></pre></div><p>移动端发版的底线是:不要把已知不确定性交给用户承担。</p>`,66)])])}const b=l(e,[["render",p]]);export{u as __pageData,b as default};
